use crate::ansi::{parse_ansi_styled, StyledChar};
use crate::tmux::{TmuxError, TmuxSession};

pub struct PaneCapture {
    pub pane_id: String,
    pub lines: Vec<Vec<StyledChar>>,
    pub raw: String,
    pub captured_at: std::time::Instant,
}

impl PaneCapture {
    pub fn capture(session: &TmuxSession, pane_id: &str, scrollback: Option<i32>) -> Result<Self, TmuxError> {
        let raw = session.capture_pane(pane_id, scrollback)?;
        let lines = parse_ansi_styled(&raw);
        Ok(Self { pane_id: pane_id.to_owned(), lines, raw, captured_at: std::time::Instant::now() })
    }
    pub fn line_count(&self) -> usize { self.lines.len() }
    pub fn char_count(&self) -> usize { self.lines.iter().map(|l| l.len()).sum() }
}
```

